export const 鎮宅不宜 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 桿 = (x0, x1, z) => {
        線(p => p.M(X(x0) + 0.32 * k, Z(z)).L(X(x1) - 0.32 * k, Z(z)));
        圈(x0, z);
        圈(x1, z);
    };
    // 符頭：桿三＋散圈行＋土土土列
    桿(0.6, 7.4, 1.0);
    桿(0.6, 7.4, 2.45);
    桿(0.6, 7.3, 3.85);
    for (const [x, z] of [[0.5, 5.4], [2.2, 5.2], [4.3, 5.2], [6.5, 5.2], [7.6, 5.5]])
        圈(x, z);
    const 土 = (cx) => {
        線(p => p.M(X(cx), Z(6.5)).L(X(cx - 0.05), Z(7.7)));
        線(p => p.M(X(cx - 0.5), Z(6.9)).L(X(cx + 0.5), Z(6.85)));
        線(p => p.M(X(cx - 0.6), Z(7.7)).L(X(cx + 0.6), Z(7.65)));
    };
    土(2.5);
    土(4.1);
    土(5.7);
    // 雙桁
    線(p => p.M(X(0.7), Z(8.2)).L(X(7.5), Z(8.1)), 0.42);
    線(p => p.M(X(0.8), Z(8.9)).L(X(7.4), Z(8.8)), 0.42);
    // 大冂匣
    線(p => p.M(X(0.7), Z(9.6)).L(X(0.7), Z(18.0)));
    線(p => p.M(X(0.7), Z(9.65)).L(X(7.5), Z(9.55)));
    線(p => p.M(X(7.5), Z(9.55)).L(X(7.5), Z(17.9)));
    // 內田田對
    const 田 = (x0) => {
        線(p => p.M(X(x0), Z(10.3)).L(X(x0), Z(13.7)).L(X(x0 + 1.9), Z(13.65))
            .L(X(x0 + 1.9), Z(10.25)).L(X(x0 - 0.05), Z(10.3)));
        線(p => p.M(X(x0 + 0.05), Z(12.0)).L(X(x0 + 1.85), Z(11.95)));
        線(p => p.M(X(x0 + 0.95), Z(10.35)).L(X(x0 + 0.92), Z(13.65)));
    };
    田(1.5);
    田(4.2);
    // 下用冎對承弓曲
    線(p => p.M(X(1.4), Z(14.2)).L(X(1.4), Z(17.7)));
    線(p => p.M(X(1.4), Z(14.25)).L(X(3.5), Z(14.2)).L(X(3.5), Z(17.6)));
    線(p => p.M(X(1.5), Z(15.6)).L(X(3.4), Z(15.55)));
    線(p => p.M(X(2.45), Z(14.3)).L(X(2.4), Z(17.5)));
    // 冎（右，內迴弓曲）
    線(p => p.M(X(4.2), Z(14.3)).L(X(4.2), Z(17.6)));
    線(p => p.M(X(4.2), Z(14.35)).L(X(6.2), Z(14.3)).L(X(6.2), Z(17.5)));
    線(p => p.M(X(4.3), Z(15.4))
        .C(X(4.7), Z(15.9), X(5.1), Z(15.9), X(5.3), Z(15.4))
        .C(X(5.5), Z(15.0), X(5.9), Z(15.0), X(6.1), Z(15.4)));
    線(p => p.M(X(4.3), Z(16.6))
        .C(X(4.7), Z(17.1), X(5.1), Z(17.1), X(5.3), Z(16.6))
        .C(X(5.5), Z(16.2), X(5.9), Z(16.2), X(6.1), Z(16.6)));
    // 迴脚
    線(p => p.M(X(0.7), Z(18.0)).C(X(0.6), Z(18.6), X(0.6), Z(19.0), X(0.7), Z(19.3)));
    線(p => p.M(X(7.5), Z(17.9)).C(X(7.6), Z(18.5), X(7.6), Z(18.9), X(7.5), Z(19.2)));
};
